    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
        <circle cx="12" cy="12" r="3"/>
    </svg>
);

const RecapSection = ({ personal, group, streakCount, freezeAvailable }) => {
    const posts = personal?.posts_written || 0;
    const words = personal?.total_words || 0;
    const reactions = personal?.reactions_received || 0;
    const views = personal?.views_received || 0;

    const tiles = [
        { icon: <PenIcon />, value: posts, label: 'posts', microCopy: getPostsCopy(posts) },
        { icon: <TypeIcon />, value: words, label: 'words', microCopy: getWordsCopy(words) },
        { icon: <HeartIcon />, value: reactions, label: 'reactions', microCopy: getReactionsCopy(reactions) },
        { icon: <EyeIcon />, value: views, label: 'views', microCopy: getViewsCopy(views) },
    ];

    return (
        <div className="dashboard-recap-v2">
            <motion.p
                className="recap-encouragement"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ duration: 0.3, delay: 0.05 }}
            >
                {getOverallEncouragement(personal, streakCount)}
            </motion.p>

            <div className="recap-tiles-grid">
                {tiles.map((tile, i) => (
                    <StatTile key={tile.label} {...tile} index={i} />
                ))}
            </div>

            <BestPostCard bestPost={personal?.best_post} />

            <CommunityHighlights group={group} />
        </div>
    );
};

export default RecapSection;

import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { motion, AnimatePresence } from 'framer-motion';
import { getWeeklyRecap, getTodaysPrompt, getPromptResponses } from '../../../API/Api';
import { useAuth } from '../../Context/useAuth';
import useStreakData from '../Streak/useStreakData';
import StreakBadge from '../Streak/StreakBadge';
import RecapSection from './RecapSection';
import PromptSection from './PromptSection';
import './DashboardBriefing.css';

const getWeekKey = () => {
    const now = new Date();
    const day = now.getUTCDay();
    const diff = day === 0 ? 6 : day - 1;
    const monday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - diff));
    return `recap-dismissed-${monday.toISOString().slice(0, 10)}`;
};

const formatDate = () => {
    return new Date().toLocaleDateString('en-US', {
        weekday: 'long',
        month: 'long',
        day: 'numeric',
    });
};

const DashboardBriefing = ({ onWriteResponse }) => {
    const { session, user } = useAuth();
    const weekKey = getWeekKey();

    const [recapCollapsed, setRecapCollapsed] = useState(() => {
        try { return localStorage.getItem(weekKey) === 'true'; }
        catch { return false; }
    });

    // ─── Data fetching ───

    const { data: recapData, isLoading: recapLoading } = useQuery({
        queryKey: ['weeklyRecap', session?.access_token],
        queryFn: () => getWeeklyRecap(session?.access_token),
        enabled: !!session?.access_token,
        staleTime: 1000 * 60 * 10,
        refetchOnWindowFocus: false,
    });

    const { data: prompt, isLoading: promptLoading } = useQuery({
        queryKey: ['todaysPrompt'],
        queryFn: getTodaysPrompt,
        staleTime: 1000 * 60 * 30,
        refetchOnWindowFocus: false,
    });

    const { data: responsesData } = useQuery({
        queryKey: ['promptResponses', prompt?.id],
        queryFn: () => getPromptResponses(prompt.id),
        enabled: !!prompt?.id,
        staleTime: 1000 * 60 * 5,
        refetchOnWindowFocus: false,
    });

    const { data: streakData } = useStreakData(user?.id);

    // ─── Derived state ───

    const recap = recapData?.recap;
    const personal = recap?.personal || {};
    const group = recap?.group || {};

    const hasRecap = !recapLoading && recap &&
        (personal.posts_written > 0 || group.total_posts > 0);
    const hasPrompt = !promptLoading && !!prompt;

    // Nothing to show
    if (!hasRecap && !hasPrompt) return null;

    const handleToggleRecap = (e) => {
        e.stopPropagation();
        const next = !recapCollapsed;
        try { localStorage.setItem(weekKey, next ? 'true' : 'false'); }
        catch { /* no-op */ }
        setRecapCollapsed(next);
    };

    const streakCount = streakData?.current_streak || 0;

    return (
        <AnimatePresence>
            <motion.div
                className="dashboard-briefing"
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -15, transition: { duration: 0.25 } }}
                transition={{ duration: 0.35, ease: 'easeOut' }}
                key="dashboard-briefing"
            >
                <div className="dashboard-briefing-header">
                    <div className="dashboard-briefing-header-left">
                        <span className="dashboard-briefing-title">Today</span>
                        <span className="dashboard-briefing-date">{formatDate()}</span>
                        {streakCount > 0 && <StreakBadge count={streakCount} size={14} showProgress freezeAvailable={streakData?.freeze_available} />}
                    </div>
                    {hasRecap && (
                        <button
                            className={`dashboard-briefing-toggle ${recapCollapsed ? 'is-collapsed' : ''}`}
                            onClick={handleToggleRecap}
                            title={recapCollapsed ? 'Show stats' : 'Hide stats'}
                        >
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                                <path d="M6 9L12 15L18 9" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                            </svg>
                        </button>
                    )}
                </div>

                <div className="dashboard-briefing-body">
                    <AnimatePresence initial={false}>
                        {hasRecap && !recapCollapsed && (
                            <motion.div
                                key="recap"
                                initial={{ height: 0, opacity: 0 }}
                                animate={{ height: 'auto', opacity: 1 }}
                                exit={{ height: 0, opacity: 0 }}
                                transition={{ duration: 0.25, ease: 'easeOut' }}
                                style={{ overflow: 'hidden' }}
                            >
                                <RecapSection personal={personal} group={group} streakCount={streakCount} />
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {hasRecap && hasPrompt && !recapCollapsed && (
                        <div className="dashboard-divider" />
                    )}

                    {hasPrompt && (
                        <PromptSection
                            prompt={prompt}
                            responsesData={responsesData}
                            onWriteResponse={onWriteResponse}
                        />
                    )}
                </div>
            </motion.div>
        </AnimatePresence>
    );
};

export default DashboardBriefing;

